          ms.claimed = true;
          emit('toast', `${rune.name} Affinity ${ms.level}: ${ms.reward}`, 'success');
        }
      }
    }
  }
  emit('state-changed');
}

export function getEffectiveStats() {
  const s = getState();
  const base = { ...s.player.stats };
