  const s = getState();
  for (const eff of effects) {
    switch (eff.type) {
      case 'rune':
        if (eff.id) discoverRune(eff.id);
        break;
      case 'item': {
        const template = ALL_ITEMS.find(i => i.id === eff.id);
        if (template) addItem({ ...template, quantity: 1 });
        break;
