  statusFilter: "all" | ReviewState;
  hypothesisFilter: string | null;
  searchQuery: string;
  selectedRunKey: string | null;
}

interface FilterActions {
  setRoundFilter: (round: string | null) => void;
  setDomainFilter: (domain: string | null) => void;
