import { useFilterStore } from "@/lib/filter-store";
import { roundForRun } from "@/components/landing/HypothesisTracksSection";
import roundsData from "@/data/rounds.json";

const REPO = "https://github.com/MagicbornStudios/get-anything-done";
const WORKFLOW_TINT: Record<Workflow, string> = {
  gad: "border-l-sky-400/70",
  bare: "border-l-emerald-400/70",
  emergent: "border-l-amber-400/70",
};

const ROUND_OPTIONS = ROUND_SUMMARIES.map((s) => s.round);

type RoundData = { kicker: string; headline: string; headlineHighlight: string; description: string };
const ROUNDS_MAP = roundsData as Record<string, RoundData>;

/** Render a headline with the highlight portion wrapped in gradient-text */
function RoundHeadline({ data }: { data: RoundData }) {
  const idx = data.headline.indexOf(data.headlineHighlight);
  if (idx < 0) return <>{data.headline}</>;
  const before = data.headline.slice(0, idx);
  const after = data.headline.slice(idx + data.headlineHighlight.length);
  return <>{before}<span className="gradient-text">{data.headlineHighlight}</span>{after}</>;
}

const DEFAULT_HEADLINE: RoundData = {
  kicker: "All results",
  headline: "Every scored run. Every condition.",
  headlineHighlight: "Every condition.",
  description: "All evaluation runs with human review scores, across all rounds and conditions.",
};

